function formatBpsValue(value: number): string {
  if (!Number.isFinite(value)) return "0";
  return Number(value.toFixed(3)).toString();
}

function formatPercentFromBps(value: string | number): string {
  const parsed =
    typeof value === "string"
      ? Number(value.replace(/\s*bps$/i, ""))
      : Number(value);
  if (!Number.isFinite(parsed)) return "0%";
  return `${Number((parsed / 100).toFixed(4)).toString()}%`;
}

