function normalizeFeeInput(value: string): string {
  const num = Number(value);
  if (!Number.isFinite(num)) return value;
  return formatBpsValue(Math.ceil(num * 10) / 10);
}

function roundFeeRangeBoundary(value: number): number {
  return Math.ceil(value * 10) / 10;
}

function isValidFeeInputPrecision(value: string): boolean {
  return value === "" || /^-?\d*(?:\.\d{0,1})?$/.test(value);
}

function normalizeFeeConfig(fees: FeeConfig): FeeConfig {
  return {
    cryptoMaker: normalizeFeeInput(fees.cryptoMaker),
    cryptoTaker: normalizeFeeInput(fees.cryptoTaker),
    rwaMaker: normalizeFeeInput(fees.rwaMaker),
    rwaTaker: normalizeFeeInput(fees.rwaTaker),
  };
}

function feeErrorFieldFromMessage(message: string): keyof FeeConfig {
  const normalized = message.toLowerCase();
  if (normalized.includes("rwa") && normalized.includes("taker"))
    return "rwaTaker";
  if (normalized.includes("rwa") && normalized.includes("maker"))
    return "rwaMaker";
  if (normalized.includes("taker") || normalized.includes("taker_fee_rate"))
    return "cryptoTaker";
  if (normalized.includes("maker") || normalized.includes("maker_fee_rate"))
    return "cryptoMaker";
  return "cryptoMaker";
}

