function decimalRateToBps(value?: string | number): string {
  const parsed = Number(value ?? 0);
  return formatBpsValue(parsed * 10_000);
}

function bpsToDecimalRate(value: string): number {
  return Number((Number.parseFloat(value) / 10_000).toFixed(8));
}

function brokerInfoToBaseFees(data: BrokerInfoResponse["data"]): {
  cryptoMaker: number;
  cryptoTaker: number;
  rwaMaker: number;
  rwaTaker: number;
} {
  return {
    cryptoMaker: Number(data?.base_maker_fee_rate ?? 0),
    cryptoTaker: Number(data?.base_taker_fee_rate ?? 0),
    rwaMaker: Number(data?.base_rwa_maker_fee_rate ?? 0),
    rwaTaker: Number(data?.base_rwa_taker_fee_rate ?? 0),
  };
}

function normalizeTierName(value?: string): string | null {
  if (!value) return null;
  const lower = value.toLowerCase();
  return lower.charAt(0).toUpperCase() + lower.slice(1);
}

function isDefaultFeeRate(value: string | boolean | undefined): boolean {
  return value === true || value === "true";
}

function userFeeRowToCustomUser(row: UserFeeRateRow): CustomFeeUser {
  const accountId = row.account_id || row.address || crypto.randomUUID();
  return {
    id: accountId,
    accountId: row.account_id,
    address: row.address || row.account_id || "",
    isDefaultFeeRate: isDefaultFeeRate(row.is_default_fee_rate),
    makerFee: decimalRateToBps(row.maker_fee_rate),
    takerFee: decimalRateToBps(row.taker_fee_rate),
    rwaMakerFee: decimalRateToBps(row.rwa_maker_fee_rate),
    rwaTakerFee: decimalRateToBps(row.rwa_taker_fee_rate),
  };
}

function feeConfigToApiPayload(fees: FeeConfig) {
  return {
    maker_fee_rate: bpsToDecimalRate(fees.cryptoMaker),
    taker_fee_rate: bpsToDecimalRate(fees.cryptoTaker),
    rwa_maker_fee_rate: bpsToDecimalRate(fees.rwaMaker),
    rwa_taker_fee_rate: bpsToDecimalRate(fees.rwaTaker),
  };
}

function customUserToApiPayload(
  user: Pick<
    CustomFeeUser,
    "makerFee" | "takerFee" | "rwaMakerFee" | "rwaTakerFee"
  >
) {
  return {
    maker_fee_rate: bpsToDecimalRate(user.makerFee),
    taker_fee_rate: bpsToDecimalRate(user.takerFee),
    rwa_maker_fee_rate: bpsToDecimalRate(user.rwaMakerFee),
    rwa_taker_fee_rate: bpsToDecimalRate(user.rwaTakerFee),
  };
}

function queryString(params: Record<string, string | number | undefined>) {
  const search = new URLSearchParams();
  Object.entries(params).forEach(([key, value]) => {
    if (value !== undefined && value !== "") search.set(key, String(value));
  });
  const value = search.toString();
  return value ? `?${value}` : "";
}

type FeeSettingsSnapshot = {
  brokerInfo: BrokerInfoResponse;
  dexFees: DexCreatorFeesResponse;
  userFees: UserFeeRatesResponse;
};

let feeSettingsCache: { value: FeeSettingsSnapshot; expiresAt: number } | null =
  null;
let feeSettingsInflight: Promise<FeeSettingsSnapshot> | null = null;

function invalidateFeeSettingsCache() {
  feeSettingsCache = null;
  feeSettingsInflight = null;
}

async function fetchFeeSettingsSnapshot(): Promise<FeeSettingsSnapshot> {
  const now = Date.now();
  if (feeSettingsCache && feeSettingsCache.expiresAt > now)
    return feeSettingsCache.value;
  if (feeSettingsInflight) return feeSettingsInflight;

  feeSettingsInflight = Promise.all([
    signedAdminRequest({ endpoint: BROKER_INFO_API }, brokerInfoResponseSchema),
    fetchDexCreatorFees(),
    signedAdminRequest(
      {
        endpoint: `${USER_INFO_API}${queryString({ page: 1, size: CUSTOM_USER_PAGE_SIZE })}`,
      },
      userFeeRatesResponseSchema
    ),
  ])
    .then(([brokerInfo, dexFeesResponse, userFees]) => {
      const value = { brokerInfo, dexFees: dexFeesResponse, userFees };
      feeSettingsCache = { value, expiresAt: Date.now() + 30_000 };
      return value;
    })
    .finally(() => {
      feeSettingsInflight = null;
    });

  return feeSettingsInflight;
}

function isValidAddress(address: string): boolean {
  return /^0x[a-fA-F0-9]{40}$/.test(address);
}

function validateFee(
  value: string,
  min: number,
  max: number,
  t: (key: string, params?: Record<string, unknown>) => string
): string {
  const num = parseFloat(value);
  if (value === "" || Number.isNaN(num))
    return t("feeSettings.enterValidNumber");
  if (num < min || num > max)
    return t("feeSettings.validRange", {
      min: formatBpsValue(min),
      max: formatBpsValue(max),
    });
  return "";
}

function getLoginMethod(): "wallet" | "api" | null {
  if (typeof window === "undefined") return null;
  const raw = walletGetItem("orderlyLoginContext");
  if (!raw) return null;
  try {
    const context = JSON.parse(raw) as { method?: "wallet" | "api" };
    return context.method || null;
  } catch {
    return null;
  }
}

