  function showToastMsg(message: string) {
    setToast(message);
    setTimeout(() => setToast(null), 3000);
  }

  function validateFeeField(key: keyof FeeConfig, value: string) {
    const num = parseFloat(value);
    const minimums: Record<keyof FeeConfig, number> = {
      cryptoMaker: roundFeeRangeBoundary(builderMinFees.cryptoMaker),
      cryptoTaker: roundFeeRangeBoundary(builderMinFees.cryptoTaker),
      rwaMaker: roundFeeRangeBoundary(builderMinFees.rwaMaker),
      rwaTaker: roundFeeRangeBoundary(builderMinFees.rwaTaker),
    };
    const min = minimums[key];
    if (value === "" || Number.isNaN(num))
      return t("feeSettings.enterValidNumber");
    if (num < min || num > 15)
      return t("feeSettings.validRange", {
        min: formatBpsValue(min),
        max: formatBpsValue(15),
      });
    return "";
  }

  function validateSwapFeeField(value: string) {
    const trimmed = value.trim();
    if (trimmed === "") return "";
    if (!/^-?\d+$/.test(trimmed)) return t("feeSettings.swapFeeWholeNumber");
    const num = Number(trimmed);
    if (num < 0 || num > 100)
      return t("feeSettings.validRange", { min: 0, max: 100 });
    return "";
  }

