  function updateDraftFeeField(key: keyof FeeConfig, value: string) {
    if (!isValidFeeInputPrecision(value)) return;
    setDraftFees(prev => ({ ...prev, [key]: value }));
    setFeeErrors(prev => {
      if (!prev[key]) return prev;
      const next = { ...prev };
      delete next[key];
      return next;
    });
  }

  function normalizeDraftFeeField(key: keyof FeeConfig) {
    setDraftFees(prev => ({ ...prev, [key]: normalizeFeeInput(prev[key]) }));
  }

