  async function handleSavePerpFees() {
    const normalizedFees = normalizeFeeConfig(draftFees);
    setDraftFees(normalizedFees);
    const newErrors: Partial<Record<keyof FeeConfig, string>> = {};
    (Object.keys(normalizedFees) as Array<keyof FeeConfig>).forEach(key => {
      const err = validateFeeField(key, normalizedFees[key]);
      if (err) newErrors[key] = err;
    });
    setFeeErrors(newErrors);
    if (Object.keys(newErrors).length > 0) return;

    setSavingPerpFees(true);
    try {
      const response = await signedAdminRequest(
        {
          endpoint: DEFAULT_BUILDER_FEE_API,
          method: "POST",
          data: feeConfigToApiPayload(normalizedFees),
        },
        basicResponseSchema
      );
      if (response.success === false)
        throw new Error(
          response.message || "Failed to update default fee rates."
        );
      invalidateFeeSettingsCache();
      walletSetItem("orderlyFees", JSON.stringify(normalizedFees));
      setSavedFees(normalizedFees);
      setShowPerpModal(false);
      setPerpApiStatus("Default fee rates synced with Orderly API.");
      showToastMsg(t("feeSettings.perpFeesSaved"));
    } catch (error) {
      const message =
        error instanceof Error
          ? error.message
          : "Failed to update default fee rates.";
      setFeeErrors({ [feeErrorFieldFromMessage(message)]: message });
    } finally {
      setSavingPerpFees(false);
    }
  }

  async function handleSaveSwapFee() {
    const validationError = validateSwapFeeField(draftSwapFee);
    if (validationError) {
      setSwapError(validationError);
      return;
    }
    const normalizedSwapFee = draftSwapFee.trim();
    const num = Number(normalizedSwapFee);

    let dexId =
      typeof window !== "undefined" ? walletGetItem("orderlyDexId") : null;
    if (normalizedSwapFee !== "") {
      setApiStatus("Saving swap fee through dex-creator API...");
      try {
        if (!dexId) {
          const dexStatus = await fetchDexCreatorDexStatus();
          dexId = dexStatus?.id || null;
          if (dexId) walletSetItem("orderlyDexId", dexId);
        }
        if (!dexId)
          throw new Error("No DEX id returned from dex-creator /api/dex.");
        await updateDexSwapFee(dexId, num);
        setApiStatus(null);
      } catch (error) {
        setApiStatus(
          error instanceof Error
            ? `API sync failed, saved locally: ${error.message}`
            : "API sync failed, saved locally."
        );
      }
    } else {
      setApiStatus(
        "Saved locally. Enter a swap fee to enable dex-creator API sync."
      );
    }

    walletSetItem(
      "orderlySwapFee",
      JSON.stringify({ swapFee: normalizedSwapFee })
    );
    setSwapFee(normalizedSwapFee);
    setShowSwapModal(false);
    showToastMsg(t("feeSettings.swapFeeSaved"));
  }

