  async function loadCustomFeeUsers(query = "", page = 1) {
    const trimmed = query.trim();
    if (trimmed && !isValidAddress(trimmed)) {
      showToastMsg(t("feeSettings.invalidEvmAddress"));
      return;
    }
    setCustomUserLookupLoading(true);
    try {
      const userFees = await signedAdminRequest(
        {
          endpoint: `${USER_INFO_API}${queryString({
            page,
            size: CUSTOM_USER_PAGE_SIZE,
            address: trimmed || undefined,
          })}`,
        },
        userFeeRatesResponseSchema
      );
      if (userFees.success === false)
        throw new Error(
          userFees.message || "Failed to load custom user fee rates."
        );
      const users = (userFees.data?.rows || []).map(userFeeRowToCustomUser);
      const meta = userFees.data?.meta;
      setCustomUsers(users);
      setCustomUserPage(Number(meta?.current_page ?? page));
      setCustomUserTotal(Number(meta?.total ?? 0));
      setCustomUserPageSize(
        Number(meta?.records_per_page ?? CUSTOM_USER_PAGE_SIZE)
      );
      walletSetItem("orderlyCustomFeeUsers", JSON.stringify(users));
    } catch (error) {
      showToastMsg(
        error instanceof Error
          ? error.message
          : "Failed to load custom user fee rates."
      );
    } finally {
      setCustomUserLookupLoading(false);
    }
  }

