  async function handleConfirmAddUser() {
    const normalizedDraft = {
      ...addUserDraft,
      makerFee: normalizeFeeInput(addUserDraft.makerFee),
      takerFee: normalizeFeeInput(addUserDraft.takerFee),
      rwaMakerFee: normalizeFeeInput(addUserDraft.rwaMakerFee),
      rwaTakerFee: normalizeFeeInput(addUserDraft.rwaTakerFee),
    };
    setAddUserDraft(normalizedDraft);
    const errs: Partial<Record<keyof Omit<CustomFeeUser, "id">, string>> = {};

    if (!isValidAddress(normalizedDraft.address.trim()))
      errs.address = t("feeSettings.invalidEvmAddress");

    const mErr = validateFee(
      normalizedDraft.makerFee,
      roundedBuilderMinFees.cryptoMaker,
      15,
      t
    );
    if (mErr) errs.makerFee = mErr;

    const tErr = validateFee(
      normalizedDraft.takerFee,
      roundedBuilderMinFees.cryptoTaker,
      15,
      t
    );
    if (tErr) errs.takerFee = tErr;

    const rmErr = validateFee(
      normalizedDraft.rwaMakerFee,
      roundedBuilderMinFees.rwaMaker,
      15,
      t
    );
    if (rmErr) errs.rwaMakerFee = rmErr;

    const rtErr = validateFee(
      normalizedDraft.rwaTakerFee,
      roundedBuilderMinFees.rwaTaker,
      15,
      t
    );
    if (rtErr) errs.rwaTakerFee = rtErr;

    if (Object.keys(errs).length > 0) {
      setAddUserErrors(errs);
      return;
    }

    setSavingCustomFee(true);
    try {
      const userInfo = await signedAdminRequest(
        {
          endpoint: `${USER_INFO_API}${queryString({ address: normalizedDraft.address.trim() })}`,
        },
        userFeeRatesResponseSchema
      );
      if (userInfo.success === false)
        throw new Error(userInfo.message || "Failed to load user account.");
      const accountId = userInfo.data?.rows?.[0]?.account_id;
      if (!accountId)
        throw new Error("No Orderly account found for this wallet address.");
      const response = await signedAdminRequest(
        {
          endpoint: SET_USER_FEE_API,
          method: "POST",
          data: {
            ...customUserToApiPayload(normalizedDraft),
            account_ids: [accountId],
          },
        },
        basicResponseSchema
      );
      if (response.success === false)
        throw new Error(response.message || "Failed to update user fee rates.");
      invalidateFeeSettingsCache();

      const newUser: CustomFeeUser = {
        id: accountId,
        accountId,
        address: normalizedDraft.address.trim(),
        isDefaultFeeRate: false,
        makerFee: normalizedDraft.makerFee,
        takerFee: normalizedDraft.takerFee,
        rwaMakerFee: normalizedDraft.rwaMakerFee,
        rwaTakerFee: normalizedDraft.rwaTakerFee,
      };

      const next = [
        ...customUsers.filter(
          user =>
            user.accountId !== accountId &&
            user.address.toLowerCase() !== newUser.address.toLowerCase()
        ),
        newUser,
      ];
      setCustomUsers(next);
      walletSetItem("orderlyCustomFeeUsers", JSON.stringify(next));
      setShowAddUserModal(false);
      showToastMsg(t("feeSettings.customFeeUserAdded"));
    } catch (error) {
      setAddUserErrors({
        address:
          error instanceof Error
            ? error.message
            : "Failed to update user fee rates.",
      } as Partial<Record<keyof Omit<CustomFeeUser, "id">, string>>);
    } finally {
      setSavingCustomFee(false);
    }
  }

  async function resetCustomUser(id: string) {
    const user = customUsers.find(item => item.id === id);
    if (!user?.accountId) {
      showToastMsg("Missing account ID for this user.");
      return;
    }

    setSavingCustomFee(true);
    try {
      const response = await signedAdminRequest(
        {
          endpoint: RESET_USER_FEE_API,
          method: "POST",
          data: { account_ids: [user.accountId] },
        },
        basicResponseSchema
      );
      if (response.success === false)
        throw new Error(response.message || "Failed to reset user fee rates.");
      invalidateFeeSettingsCache();
      const next = customUsers.filter(item => item.id !== id);
      setCustomUsers(next);
      walletSetItem("orderlyCustomFeeUsers", JSON.stringify(next));
      setCustomUserErrors(prev => {
        const nextErrors = { ...prev };
        delete nextErrors[id];
        return nextErrors;
      });
      showToastMsg(t("feeSettings.feesResetToDefault"));
    } catch (error) {
      showToastMsg(
        error instanceof Error
          ? error.message
          : "Failed to reset user fee rates."
      );
    } finally {
      setSavingCustomFee(false);
    }
  }

